"""
Build curated vocabulary JSON files for all 8 supported languages.
Each file: data/vocab/<language>.json
Each entry: {word, romanization, english, part_of_speech, difficulty, topic}

Run once: python data/vocab/build_vocab.py
"""

import json, pathlib

def save(lang, entries):
    path = pathlib.Path(__file__).parent / f"{lang}.json"
    with open(path, "w", encoding="utf-8") as f:
        json.dump(entries, f, ensure_ascii=False, indent=2)
    print(f"Saved {len(entries)} entries → {path.name}")

